patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..e1816dfb9ac8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8633,14 +8633,35 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   Constant *RHSC;
   if (match(Op0, m_Instruction(LHSI)) && match(Op1, m_Constant(RHSC))) {
     switch (LHSI->getOpcode()) {
-    case Instruction::Select:
+    case Instruction::Select: {
       // fcmp eq (cond ? x : -x), 0 --> fcmp eq x, 0
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+
+      // fcmp pred (select (fcmp ord X, _), X, FalseVal), C -> fcmp pred X, C
+      // if fcmp pred FalseVal, C gives the same result as fcmp pred NaN, C
+      // (which is false for ordered predicates, true for unordered).
+      Value *FalseVal;
+      CmpPredicate OrdPred = FCmpInst::FCMP_ORD;
+      if (match(LHSI,
+                m_Select(m_FCmp(OrdPred, m_Value(X), m_Value()),
+                         m_Deferred(X), m_Value(FalseVal)))) {
+        bool IsOrdered = FCmpInst::isOrdered(Pred);
+        if (Value *V = simplifyFCmpInst(Pred, FalseVal, RHSC,
+                                        I.getFastMathFlags(),
+                                        SQ.getWithInstruction(&I))) {
+          bool FalseValCmpIsFalse = match(V, m_Zero());
+          bool FalseValCmpIsTrue = match(V, m_One());
+          if ((IsOrdered && FalseValCmpIsFalse) ||
+              (!IsOrdered && FalseValCmpIsTrue))
+            return replaceOperand(I, 0, X);
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;
+    }
     case Instruction::FSub:
       if (LHSI->hasOneUse())
         if (Instruction *NV = foldFCmpFSubIntoFCmp(I, LHSI, RHSC, *this))
